{
  "shots": [
    {
      "shot_id": "SH12",
      "priority": "P0",
      "intent": "承接健一上一镜回答后，由石川电话远端说明浅蓝丝巾正在被实验室比对为凶器线索，让遗物瞬间转为案件物证。",
      "duration_sec": 5,
      "shot_type": "双人中近景",
      "movement": "固定机位",
      "framing_focus": "首帧稳定双人中近景：健一整理遗物的客厅地板旁，佐藤美咲位于画面右侧，右手指尖停在 AYAKA_COSMETIC_BOX_01 盒盖上并成为视觉中心；田中健一位于左中部，右手持 KENICHI_SMARTPHONE_01 靠近右耳，目光落向画面下方的 AYAKA_LIGHT_BLUE_SILK_SCARF_01。人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "action_intent": "本镜头只承载石川电话远端说明丝巾物证；健一保持听电话姿势沉默，美咲嘴唇静止，右手停在化妆品盒上，浅蓝丝巾保持可见。",
      "emotion_intent": "线索压近时的寒意与停顿：健一的可靠外表下显出不安，美咲警觉收紧但不解释。",
      "scene_id": "EP06_LIVINGROOM_PHONE_SCARF_CLUE",
      "scene_name": "健一整理遗物的客厅",
      "dialogue": [
        {
          "speaker": "石川悠一",
          "text": "实验室在比对。凶器是彩花爱用的那条丝巾，或许有线索。",
          "purpose": "通过电话把浅蓝丝巾从遗物推进为案件物证线索。",
          "source": "phone",
          "listener": "田中健一"
        }
      ],
      "narration": [],
      "subtitle": [
        "实验室在比对。凶器是彩花爱用的那条丝巾，或许有线索。"
      ],
      "positive_core": "首帧稳定在健一整理遗物的客厅地板旁，佐藤美咲右手指尖停在 AYAKA_COSMETIC_BOX_01 盒盖上成为视觉中心，田中健一在左侧持 KENICHI_SMARTPHONE_01 贴近右耳，AYAKA_LIGHT_BLUE_SILK_SCARF_01 半铺在二人之间的地板上。电话里传来石川悠一的声音，健一沉默听着，视线停在浅蓝丝巾；美咲保持半起身姿态，嘴唇静止，视线微微紧缩。黑色手机屏幕朝内贴近持有人，屏幕内容不呈现。现代日本都市悬疑写实电影感，竖屏9:16，低饱和，客厅暖白台灯与窗外冷蓝夜色形成克制反差，人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "first_frame_contract": {
        "location": "健一整理遗物的客厅地板旁",
        "visual_center": "佐藤美咲停在 AYAKA_COSMETIC_BOX_01 盒盖上的右手指尖",
        "visible_characters": [
          "田中健一",
          "佐藤美咲"
        ],
        "character_positions": {
          "田中健一": "画面左中部，坐在地板旁，右手持手机靠近右耳，目光低落到浅蓝丝巾",
          "佐藤美咲": "画面右侧半起身停住，右手指尖停在化妆品盒盒盖上，脸部在右上方可见"
        },
        "key_props": [
          "KENICHI_SMARTPHONE_01",
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01",
          "AYAKA_COSMETIC_BOX_01"
        ],
        "speaking_state": "石川悠一以电话远端声音说话；田中健一沉默听电话且无口型，佐藤美咲沉默且无口型。",
        "camera_motion_allowed": "固定机位"
      },
      "dialogue_blocking": {
        "active_speaker": "石川悠一（电话远端）",
        "first_speaker": "石川悠一（电话远端）",
        "speaker_visual_priority": "listener_visible",
        "silent_visible_characters": [
          "田中健一",
          "佐藤美咲"
        ],
        "lip_sync_policy": "remote_voice_listener_silent"
      },
      "i2v_contract": {
        "shot_task": "dialogue",
        "risk_level": "medium",
        "risk_notes": "电话远端为唯一主动说话人，画面内有两名可见人物，需保持田中健一和佐藤美咲沉默无口型；三件关键道具同屏，需保持位置与材质连续。",
        "prop_library": {
          "KENICHI_SMARTPHONE_01": {
            "display_name": "健一手机",
            "count": "1部",
            "size": "约15厘米 × 7厘米 × 0.8厘米",
            "color": "黑色机身，深色保护壳",
            "material": "玻璃屏幕，金属边框，硅胶保护壳",
            "structure": "直板智能手机，来电界面可短暂显示“陌生号码”",
            "canonical_motion_policy": "通话时由健一手持，靠近耳侧或胸前；远端声音镜头中屏幕朝内，不展示额外屏幕内容。"
          },
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01": {
            "display_name": "浅蓝丝巾",
            "count": "1条",
            "size": "约150厘米 × 35厘米",
            "color": "浅蓝色，低饱和冷调",
            "material": "丝质，表面有柔和反光",
            "structure": "长方形薄丝巾，边缘有细窄卷边",
            "canonical_motion_policy": "默认折叠或半铺在健一膝前；只允许由健一或美咲手部触碰、捏紧、放下或滑落。"
          },
          "AYAKA_COSMETIC_BOX_01": {
            "display_name": "彩花化妆品盒",
            "count": "1个",
            "size": "约14厘米 × 9厘米 × 5厘米",
            "color": "米白色外壳，银色边框",
            "material": "硬质塑料外壳，金属铰链，内部有镜面和细粉质化妆品格",
            "structure": "翻盖式小盒，盒盖可打开，内部镜面固定在盖内侧",
            "canonical_motion_policy": "默认闭合放置；需要展示时可由美咲递给健一或停在地板上，不做复杂开合。"
          }
        },
        "prop_contract": [
          {
            "prop_id": "KENICHI_SMARTPHONE_01",
            "position": "首帧位于田中健一右手中，靠近右耳，屏幕朝向持有人",
            "first_frame_visible": true,
            "motion_policy": "全程由健一稳定持握在耳侧，只允许手指轻微收紧，屏幕内容不呈现",
            "controlled_by": "田中健一"
          },
          {
            "prop_id": "AYAKA_LIGHT_BLUE_SILK_SCARF_01",
            "position": "首帧半铺在二人之间的地板上，靠近田中健一膝前，位于画面下方可见",
            "first_frame_visible": true,
            "motion_policy": "全程保持半铺状态，不被拿起，不做位置变化",
            "controlled_by": "none"
          },
          {
            "prop_id": "AYAKA_COSMETIC_BOX_01",
            "position": "首帧位于画面右侧地板上，佐藤美咲右手指尖停在闭合盒盖上",
            "first_frame_visible": true,
            "motion_policy": "保持闭合停放，美咲指尖只可有极轻微压力变化，不打开、不递出",
            "controlled_by": "佐藤美咲"
          }
        ],
        "phone_contract": {
          "holder": "田中健一",
          "screen_orientation": "screen facing inward toward holder",
          "screen_content_visible": false
        }
      },
      "source_basis": "对应 TARGET_FACTS 17：健一上一镜回答“有。怎么？”后停住，本镜头只呈现石川悠一电话远端继续说明实验室正在比对，凶器是彩花爱用的浅蓝丝巾，可能有线索；画面中健一和美咲均沉默，视线与道具共同把遗物转化为物证。"
    }
  ],
  "qa_report": [
    {
      "check": "single shot requirement",
      "result": "pass",
      "notes": "仅输出 SH12，shots 数组长度为 1，duration_sec 为 5。"
    },
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "本镜头唯一主动说话人为电话远端石川悠一；田中健一作为可见 listener 沉默无口型，佐藤美咲可见但沉默无口型，符合电话拆分与一镜一口规则。"
    },
    {
      "check": "continuity self-check",
      "result": "pass",
      "notes": "承接 SH11 中健一持手机靠近右耳、视线落到浅蓝丝巾、美咲半起身停住的状态；未重复健一上一镜“有。怎么？”的信息功能。"
    },
    {
      "check": "prop consistency self-check",
      "result": "pass",
      "notes": "KENICHI_SMARTPHONE_01、AYAKA_LIGHT_BLUE_SILK_SCARF_01、AYAKA_COSMETIC_BOX_01 均沿用道具库的数量、尺寸、颜色、材质、结构和运动策略。"
    },
    {
      "check": "first frame stability self-check",
      "result": "pass",
      "notes": "framing_focus 与 positive_core 第一句均为单一地点、单一时间的稳定首帧，未混入跨地点或完整动作链。"
    }
  ]
}
